import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CalculationMethod {
  TARGET_MARGIN = 'TARGET_MARGIN',
  REAL_PROFIT = 'REAL_PROFIT'
}

export interface UserInputs {
  productCost: number; // CP
  taxRate: number; // I% (0-100)
  operationalCost: number; // CFV
  targetMargin: number; // Margem Alvo % (0-100)
  testPrice: number; // Preço Teste
  includeAffiliate: boolean; // TikTok Only
}

export interface PlatformResult {
  platformName: string;
  sellingPrice: number;
  netProfit: number;
  netProfitMargin: number;
  totalFixedCosts: number;
  totalVariableCosts: number;
  feesBreakdown: {
    commission: number;
    transactionFee: number;
    fixedFee: number;
    tax: number;
    affiliate?: number;
  };
}

export interface CalculationContext {
  shopee: PlatformResult;
  tiktok: PlatformResult;
}

export const formatCurrency = (value: number): string => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

export const formatPercent = (value: number): string => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'percent',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value / 100);
};

export const parseCurrencyInput = (value: string): number => {
  // Remove currency symbol, dots, and replace comma with dot
  const cleanValue = value.replace(/[^0-9,]/g, '').replace(',', '.');
  return parseFloat(cleanValue) || 0;
};

import { UserInputs, PlatformResult, CalculationMethod } from '../types';

// Constants defined in the prompt
const SHOPEE_COMMISSION_RATE = 0.20; // 20%
const SHOPEE_TRANSACTION_RATE = 0.02; // 2%
const SHOPEE_FIXED_FEE = 5.00;

const TIKTOK_COMMISSION_RATE = 0.12; // 12% (Includes Trans fee)
const TIKTOK_AFFILIATE_RATE = 0.10; // 10%
const TIKTOK_FIXED_FEE_THRESHOLD = 79.00;
const TIKTOK_FIXED_FEE_VALUE = 2.00;

export const calculateResults = (inputs: UserInputs, method: CalculationMethod): { shopee: PlatformResult, tiktok: PlatformResult } => {

  // 1. Calculate Shopee
  const shopeeResult = calculateShopee(inputs, method);

  // 2. Calculate TikTok
  const tiktokResult = calculateTikTok(inputs, method);

  return { shopee: shopeeResult, tiktok: tiktokResult };
};

const calculateShopee = (inputs: UserInputs, method: CalculationMethod): PlatformResult => {
  const { productCost, operationalCost, taxRate, targetMargin, testPrice } = inputs;

  // Total Variable Rate (Denominators): Tax + Comm + Trans
  const totalVariableRate = (taxRate / 100) + SHOPEE_COMMISSION_RATE + SHOPEE_TRANSACTION_RATE;

  // Total Fixed Amount (Numerators part 1): CP + CFV + Fixed Fee
  const totalFixedAmount = productCost + operationalCost + SHOPEE_FIXED_FEE;

  let sellingPrice = 0;

  if (method === CalculationMethod.TARGET_MARGIN) {
    // PV = Fixed Costs / (1 - (Var% + Target%))
    // Target Margin input is 0-100, convert to decimal
    const marginDecimal = targetMargin / 100;
    const denominator = 1 - (totalVariableRate + marginDecimal);

    // Safety check for division by zero or negative
    if (denominator <= 0) {
      sellingPrice = 0; // Impossible to achieve margin
    } else {
      sellingPrice = totalFixedAmount / denominator;
    }
  } else {
    sellingPrice = testPrice;
  }

  // Calculate Breakdowns based on determined Selling Price
  const taxValue = sellingPrice * (taxRate / 100);
  const commissionValue = sellingPrice * SHOPEE_COMMISSION_RATE;
  const transactionValue = sellingPrice * SHOPEE_TRANSACTION_RATE;
  const totalVariableCosts = taxValue + commissionValue + transactionValue;

  // Net Profit = PV - Fixed Costs (CP + CFV + Fee) - Variable Costs
  const netProfit = sellingPrice - totalFixedAmount - totalVariableCosts;
  const netProfitMargin = sellingPrice > 0 ? (netProfit / sellingPrice) * 100 : 0;

  return {
    platformName: 'Shopee',
    sellingPrice,
    netProfit,
    netProfitMargin,
    totalFixedCosts: totalFixedAmount,
    totalVariableCosts,
    feesBreakdown: {
      commission: commissionValue,
      transactionFee: transactionValue,
      fixedFee: SHOPEE_FIXED_FEE,
      tax: taxValue
    }
  };
};

const calculateTikTok = (inputs: UserInputs, method: CalculationMethod): PlatformResult => {
  const { productCost, operationalCost, taxRate, targetMargin, testPrice, includeAffiliate } = inputs;

  const affiliateRate = includeAffiliate ? TIKTOK_AFFILIATE_RATE : 0;

  // Total Variable Rate: Tax + Comm (12%) + Affiliate
  const totalVariableRate = (taxRate / 100) + TIKTOK_COMMISSION_RATE + affiliateRate;

  // Base Fixed Costs (without platform fixed fee yet): CP + CFV
  const baseFixedCosts = productCost + operationalCost;

  let sellingPrice = 0;
  let appliedFixedFee = 0;

  if (method === CalculationMethod.TARGET_MARGIN) {
    const marginDecimal = targetMargin / 100;
    const denominator = 1 - (totalVariableRate + marginDecimal);

    if (denominator <= 0) {
      sellingPrice = 0;
    } else {
      // Scenario A: Assume Price < 79 (Apply Fee)
      const priceWithFee = (baseFixedCosts + TIKTOK_FIXED_FEE_VALUE) / denominator;

      // Scenario B: Assume Price >= 79 (No Fee)
      const priceWithoutFee = baseFixedCosts / denominator;

      // Logic to determine which price is valid based on threshold
      if (priceWithFee < TIKTOK_FIXED_FEE_THRESHOLD) {
        sellingPrice = priceWithFee;
        appliedFixedFee = TIKTOK_FIXED_FEE_VALUE;
      } else {
        // If calculation with fee pushes it over 79, check if calculation without fee keeps it over 79
        if (priceWithoutFee >= TIKTOK_FIXED_FEE_THRESHOLD) {
          sellingPrice = priceWithoutFee;
          appliedFixedFee = 0;
        } else {
          // Edge case: Mathematical gap. Usually default to the safer (higher cost) assumption or just set to 79.
          // For this calc, we stick to the formula result that is consistent.
          sellingPrice = priceWithFee; 
          appliedFixedFee = TIKTOK_FIXED_FEE_VALUE;
        }
      }
    }
  } else {
    sellingPrice = testPrice;
    appliedFixedFee = sellingPrice < TIKTOK_FIXED_FEE_THRESHOLD ? TIKTOK_FIXED_FEE_VALUE : 0;
  }

  // Calculate Breakdowns
  const taxValue = sellingPrice * (taxRate / 100);
  const commissionValue = sellingPrice * TIKTOK_COMMISSION_RATE;
  const affiliateValue = sellingPrice * affiliateRate;
  const totalVariableCosts = taxValue + commissionValue + affiliateValue;
  const totalFixedCosts = baseFixedCosts + appliedFixedFee;

  const netProfit = sellingPrice - totalFixedCosts - totalVariableCosts;
  const netProfitMargin = sellingPrice > 0 ? (netProfit / sellingPrice) * 100 : 0;

  return {
    platformName: 'TikTok Shop',
    sellingPrice,
    netProfit,
    netProfitMargin,
    totalFixedCosts,
    totalVariableCosts,
    feesBreakdown: {
      commission: commissionValue,
      transactionFee: 0, // Included in commission
      fixedFee: appliedFixedFee,
      tax: taxValue,
      affiliate: affiliateValue
    }
  };
};

import { GoogleGenAI } from "@google/genai";
import { UserInputs, PlatformResult, CalculationMethod } from "../types";
import { formatCurrency, formatPercent } from "../utils/currency";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const generatePricingAnalysis = async (
  inputs: UserInputs,
  shopeeResult: PlatformResult,
  tiktokResult: PlatformResult,
  method: CalculationMethod
): Promise<string> => {
  const client = getClient();
  if (!client) {
    return "API Key não configurada. Configure process.env.API_KEY para usar a IA.";
  }

  const methodText = method === CalculationMethod.TARGET_MARGIN 
    ? "Definição de Preço por Margem Alvo" 
    : "Análise de Lucro Real";

  const prompt = `
    Atue como um especialista sênior em E-commerce e Finanças no Brasil.
    Analise os seguintes dados de precificação para um produto:

    **Contexto:**
    - Método: ${methodText}
    - Custo do Produto: ${formatCurrency(inputs.productCost)}
    - Imposto: ${inputs.taxRate}%
    - Custo Operacional: ${formatCurrency(inputs.operationalCost)}
    ${method === CalculationMethod.TARGET_MARGIN ? `- Margem Alvo Desejada: ${inputs.targetMargin}%` : `- Preço de Venda Testado: ${formatCurrency(inputs.testPrice)}`}

    **Resultados Calculados:**

    1. **Shopee:**
       - Preço Final: ${formatCurrency(shopeeResult.sellingPrice)}
       - Lucro Líquido: ${formatCurrency(shopeeResult.netProfit)} (${formatPercent(shopeeResult.netProfitMargin)})
       - Taxas Totais (Plataforma + Imposto): ${formatCurrency(shopeeResult.totalVariableCosts + shopeeResult.feesBreakdown.fixedFee)}

    2. **TikTok Shop:**
       - Preço Final: ${formatCurrency(tiktokResult.sellingPrice)}
       - Lucro Líquido: ${formatCurrency(tiktokResult.netProfit)} (${formatPercent(tiktokResult.netProfitMargin)})
       - Taxas Totais: ${formatCurrency(tiktokResult.totalVariableCosts + tiktokResult.feesBreakdown.fixedFee)}
       - Afiliado Ativo: ${inputs.includeAffiliate ? 'Sim' : 'Não'}

    **Tarefa:**
    Forneça uma análise estratégica curta e direta (máximo 3 parágrafos) comparando as duas plataformas.
    - Qual plataforma está oferecendo melhor retorno neste cenário?
    - O preço está competitivo para o mercado brasileiro?
    - Dê uma sugestão tática para aumentar o lucro (ex: ajustar preço para fugir da taxa fixa do TikTok, renegociar fornecedor, etc).

    Use formatação Markdown para deixar a leitura agradável.
  `;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar a análise no momento.";
  } catch (error) {
    console.error("Erro ao chamar Gemini:", error);
    return "Erro ao conectar com a inteligência artificial. Tente novamente.";
  }
};

import React from 'react';
import { UserInputs, CalculationMethod } from '../types';

interface CalculatorInputsProps {
  inputs: UserInputs;
  setInputs: React.Dispatch<React.SetStateAction<UserInputs>>;
  method: CalculationMethod;
  setMethod: (m: CalculationMethod) => void;
}

const CalculatorInputs: React.FC<CalculatorInputsProps> = ({ inputs, setInputs, method, setMethod }) => {

  const handleChange = (field: keyof UserInputs, value: number | boolean) => {
    setInputs(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 h-full">
      <div className="mb-8">
        <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Método de Cálculo</label>
        <div className="mt-2 flex p-1 bg-gray-100 rounded-lg">
          <button
            onClick={() => setMethod(CalculationMethod.TARGET_MARGIN)}
            className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
              method === CalculationMethod.TARGET_MARGIN
                ? 'bg-white text-indigo-600 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            🎯 Margem Alvo
          </button>
          <button
            onClick={() => setMethod(CalculationMethod.REAL_PROFIT)}
            className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
              method === CalculationMethod.REAL_PROFIT
                ? 'bg-white text-emerald-600 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            💰 Lucro Real
          </button>
        </div>
        <p className="mt-2 text-xs text-gray-500">
          {method === CalculationMethod.TARGET_MARGIN 
            ? "Calcula o Preço de Venda necessário para atingir sua margem desejada." 
            : "Calcula quanto sobra no bolso (Lucro Líquido) a partir de um preço de venda fixo."}
        </p>
      </div>

      <div className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Custo do Produto (R$)</label>
            <input
              type="number"
              min="0"
              step="0.01"
              value={inputs.productCost}
              onChange={(e) => handleChange('productCost', parseFloat(e.target.value) || 0)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Custo Operacional (R$)</label>
            <input
              type="number"
              min="0"
              step="0.01"
              value={inputs.operationalCost}
              onChange={(e) => handleChange('operationalCost', parseFloat(e.target.value) || 0)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
            <span className="text-xs text-gray-400">Embalagem, etiqueta, fita...</span>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Imposto Simples Nacional (%)</label>
          <input
            type="number"
            min="0"
            max="100"
            step="0.1"
            value={inputs.taxRate}
            onChange={(e) => handleChange('taxRate', parseFloat(e.target.value) || 0)}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
          />
        </div>

        {method === CalculationMethod.TARGET_MARGIN ? (
          <div className="p-4 bg-indigo-50 rounded-lg border border-indigo-100">
            <label className="block text-sm font-bold text-indigo-900 mb-1">Margem de Lucro Alvo (%)</label>
            <input
              type="number"
              min="0"
              max="100"
              step="1"
              value={inputs.targetMargin}
              onChange={(e) => handleChange('targetMargin', parseFloat(e.target.value) || 0)}
              className="w-full px-3 py-2 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-indigo-900 font-semibold"
            />
            <span className="text-xs text-indigo-600 mt-1 block">Quanto você quer ganhar sobre a venda bruta.</span>
          </div>
        ) : (
          <div className="p-4 bg-emerald-50 rounded-lg border border-emerald-100">
            <label className="block text-sm font-bold text-emerald-900 mb-1">Preço de Venda Teste (R$)</label>
            <input
              type="number"
              min="0"
              step="0.01"
              value={inputs.testPrice}
              onChange={(e) => handleChange('testPrice', parseFloat(e.target.value) || 0)}
              className="w-full px-3 py-2 border border-emerald-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-900 font-semibold"
            />
             <span className="text-xs text-emerald-600 mt-1 block">O preço que você quer praticar no marketplace.</span>
          </div>
        )}

        <div className="pt-4 border-t border-gray-200">
          <label className="flex items-center space-x-3 cursor-pointer group">
            <div className="relative">
              <input
                type="checkbox"
                className="sr-only"
                checked={inputs.includeAffiliate}
                onChange={(e) => handleChange('includeAffiliate', e.target.checked)}
              />
              <div className={`block w-10 h-6 rounded-full transition-colors ${inputs.includeAffiliate ? 'bg-gray-900' : 'bg-gray-300'}`}></div>
              <div className={`dot absolute left-1 top-1 bg-white w-4 h-4 rounded-full transition-transform ${inputs.includeAffiliate ? 'transform translate-x-4' : ''}`}></div>
            </div>
            <div className="flex flex-col">
              <span className="text-sm font-medium text-gray-900">Incluir Afiliados TikTok (10%)?</span>
              <span className="text-xs text-gray-500">Adiciona comissão extra de afiliado no cálculo do TikTok.</span>
            </div>
          </label>
        </div>
      </div>
    </div>
  );
};

export default CalculatorInputs;

import React from 'react';
import { PlatformResult } from '../types';
import { formatCurrency, formatPercent } from '../utils/currency';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface ResultCardProps {
  result: PlatformResult;
  colorTheme: 'orange' | 'black'; // Shopee is orange, TikTok is black
}

const ResultCard: React.FC<ResultCardProps> = ({ result, colorTheme }) => {

  const themeClasses = {
    orange: {
      border: 'border-orange-200',
      bg: 'bg-white',
      header: 'bg-gradient-to-r from-orange-500 to-red-500',
      text: 'text-orange-600',
      fill: '#f97316'
    },
    black: {
      border: 'border-gray-200',
      bg: 'bg-white',
      header: 'bg-gray-900',
      text: 'text-gray-900',
      fill: '#111827'
    }
  };

  const currentTheme = themeClasses[colorTheme];

  const chartData = [
    { name: 'Custo Fixo (Prod + Oper)', value: result.totalFixedCosts - (result.feesBreakdown.fixedFee), color: '#9CA3AF' },
    { name: 'Taxas & Comissões', value: result.totalVariableCosts + result.feesBreakdown.fixedFee, color: '#EF4444' },
    { name: 'Lucro Líquido', value: result.netProfit > 0 ? result.netProfit : 0, color: '#10B981' },
  ];

  return (
    <div className={`rounded-xl shadow-lg overflow-hidden border ${currentTheme.border} ${currentTheme.bg} flex flex-col`}>
      <div className={`${currentTheme.header} p-4 text-white flex justify-between items-center`}>
        <h3 className="font-bold text-lg">{result.platformName}</h3>
        <span className="text-xs bg-white/20 px-2 py-1 rounded backdrop-blur-sm">
           {result.feesBreakdown.affiliate && result.feesBreakdown.affiliate > 0 ? 'Com Afiliado' : 'Padrão'}
        </span>
      </div>

      <div className="p-6 flex-1 flex flex-col">
        <div className="mb-6 text-center">
          <p className="text-sm text-gray-500 mb-1">Preço de Venda Final</p>
          <div className={`text-4xl font-bold ${currentTheme.text}`}>
            {formatCurrency(result.sellingPrice)}
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-6">
           <div className="bg-emerald-50 p-3 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase">Lucro (R$)</p>
              <p className="text-xl font-bold text-emerald-600">{formatCurrency(result.netProfit)}</p>
           </div>
           <div className="bg-emerald-50 p-3 rounded-lg border border-emerald-100 text-center">
              <p className="text-xs text-emerald-700 font-medium uppercase">Margem (%)</p>
              <p className="text-xl font-bold text-emerald-600">{formatPercent(result.netProfitMargin)}</p>
           </div>
        </div>

        <div className="mb-6 h-32 w-full relative">
           <ResponsiveContainer width="100%" height="100%">
             <PieChart>
               <Pie
                 data={chartData}
                 cx="50%"
                 cy="50%"
                 innerRadius={40}
                 outerRadius={60}
                 paddingAngle={2}
                 dataKey="value"
               >
                 {chartData.map((entry, index) => (
                   <Cell key={`cell-${index}`} fill={entry.color} />
                 ))}
               </Pie>
               <Tooltip formatter={(value: number) => formatCurrency(value)} />
             </PieChart>
           </ResponsiveContainer>
           <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
             <span className="text-xs text-gray-400 font-medium">Breakdown</span>
           </div>
        </div>

        <div className="space-y-2 text-sm border-t border-gray-100 pt-4 mt-auto">
          <div className="flex justify-between">
            <span className="text-gray-500">Custo Fixo Total (Prod+Op):</span>
            <span className="font-medium text-gray-700">{formatCurrency(result.totalFixedCosts - result.feesBreakdown.fixedFee)}</span>
          </div>
          <div className="flex justify-between">
             <span className="text-gray-500">Comissão ({colorTheme === 'orange' ? '20%' : '12%'}):</span>
             <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.commission)}</span>
          </div>
           {result.feesBreakdown.transactionFee > 0 && (
            <div className="flex justify-between">
              <span className="text-gray-500">Taxa Transação:</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.transactionFee)}</span>
            </div>
          )}
          {result.feesBreakdown.affiliate && result.feesBreakdown.affiliate > 0 && (
             <div className="flex justify-between">
               <span className="text-gray-500">Afiliado:</span>
               <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.affiliate)}</span>
             </div>
          )}
           <div className="flex justify-between">
              <span className="text-gray-500">Taxa Fixa Item:</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.fixedFee)}</span>
            </div>
           <div className="flex justify-between">
              <span className="text-gray-500">Imposto:</span>
              <span className="font-medium text-red-500">-{formatCurrency(result.feesBreakdown.tax)}</span>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ResultCard;

import React, { useState } from 'react';
import { UserInputs, PlatformResult, CalculationMethod } from '../types';
import { generatePricingAnalysis } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface AiInsightProps {
  inputs: UserInputs;
  shopeeResult: PlatformResult;
  tiktokResult: PlatformResult;
  method: CalculationMethod;
}

const AiInsight: React.FC<AiInsightProps> = ({ inputs, shopeeResult, tiktokResult, method }) => {
  const [loading, setLoading] = useState(false);
  const [analysis, setAnalysis] = useState<string | null>(null);

  const handleGenerateInsight = async () => {
    setLoading(true);
    setAnalysis(null);
    const result = await generatePricingAnalysis(inputs, shopeeResult, tiktokResult, method);
    setAnalysis(result);
    setLoading(false);
  };

  return (
    <div className="mt-8 bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl border border-indigo-100 p-6 shadow-sm">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-indigo-600 rounded-lg">
             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-white">
