                <span className="text-white font-bold text-lg">P</span>
             </div>
             <h1 className="text-xl font-bold text-gray-900 tracking-tight">Precifica<span className="text-indigo-600">Multi</span></h1>
          </div>
          <a href="#" className="text-sm font-medium text-gray-500 hover:text-indigo-600 transition-colors">
            Documentação
          </a>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Inputs */}
          <div className="lg:col-span-4">
            <CalculatorInputs 
              inputs={inputs} 
              setInputs={setInputs} 
              method={method} 
              setMethod={setMethod} 
            />
          </div>

          {/* Right Column: Results */}
          <div className="lg:col-span-8">
             <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold text-gray-800">Comparativo de Resultados</h2>
             </div>

             {results && (
               <>
