                 {/* Gemini Integration */}
                 <AiInsight 
                    inputs={inputs}
                    shopeeResult={results.shopee}
                    tiktokResult={results.tiktok}
                    method={method}
                 />
               </>
             )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

